import React from 'react';
import { Link } from 'react-router-dom';
import { getText } from '../utils/helpers';

function Home() {
  return (
    <div className="container text-center">
      <h1 className="mb-20">{getText('en', 'title')}</h1>
      <div className="mt-20">
        <Link to="/patient">
          <button className="btn">
            {getText('en', 'patientRegistration')}
          </button>
        </Link>
        <Link to="/login">
          <button className="btn">
            {getText('en', 'doctorLogin')}
          </button>
        </Link>
      </div>
    </div>
  );
}

export default Home;
